# Defines: def make_unlabeled_stru( data, frame_idx, pp_file=None, numerical_orbital=None, numerical_descriptor=None, mass=None, move=None, velocity=None, mag=None, angle1=None, angle2=None, sc=None, lambda_=None, link_file=False, dest_dir=None, **kwargs, )
# Uses: os, re, warnings, np, LengthConversion
