from __future__ import annotations

import numpy as np

from .pbc import posi_diff, posi_shift


def compute_bonds(box, posis, atype, oh_sel=[0, 1], max_roh=1.3, uniq_hbond=True):
    try:
        # nlist implemented by ase
        return compute_bonds_ase(box, posis, atype, oh_sel, max_roh, uniq_hbond)
    except ImportError:
        # nlist naivly implemented , scales as O(N^2)
        return compute_bonds_naive(box, posis, atype, oh_sel, max_roh, uniq_hbond)


def compute_bonds_ase(box, posis, atype, oh_sel=[0, 1], max_roh=1.3, uniq_hbond=True):
    natoms = len(posis)
    import ase.neighborlist
    from ase import Atoms

    atoms = Atoms(positions=posis, cell=box, pbc=[1, 1, 1])
    nlist = ase.neighborlist.NeighborList(
        max_roh,
        self_interaction=False,
        bothways=True,
        primitive=ase.neighborlist.NewPrimitiveNeighborList,
    )
    nlist.update(atoms)
    bonds = []
    o_type = oh_sel[0]
    h_type = oh_sel[1]
    for ii in range(natoms):
        bonds.append([])
    for ii in range(natoms):
        if atype[ii] == o_type:
            nn, ss = nlist.get_neighbors(ii)
            for jj in nn:
                if atype[jj] == h_type:
                    dr = posi_diff(box, posis[ii], posis[jj])
                    if np.linalg.norm(dr) < max_roh:
                        bonds[ii].append(jj)
                        bonds[jj].append(ii)
    if uniq_hbond:
        for jj in range(natoms):
            if atype[jj] == h_type:
                if len(bonds[jj]) > 1:
                    orig_bonds = bonds[jj]
                    min_bd = 1e10
                    min_idx = -1
                    for ii in bonds[jj]:
                        dr = posi_diff(box, posis[ii], posis[jj])
                        drr = np.linalg.norm(dr)
                        # print(ii,jj, posis[ii], posis[jj], drr)
                        if drr < min_bd:
                            min_idx = ii
                            min_bd = drr
                    bonds[jj] = [min_idx]
                    orig_bonds.remove(min_idx)
                    # print(min_idx, orig_bonds, bonds[jj])
                    for ii in orig_bonds:
                        bonds[ii].remove(jj)
    return bonds


def compute_bonds_naive(box, posis, atype, oh_sel=[0, 1], max_roh=1.3, uniq_hbond=True):
    natoms = len(posis)
    bonds = []
    o_type = oh_sel[0]
    h_type = oh_sel[1]
    for ii in range(natoms):
        bonds.append([])
    for ii in range(natoms):
        if atype[ii] == o_type:
            for jj in range(natoms):
                if atype[jj] == h_type:
                    dr = posi_diff(box, posis[ii], posis[jj])
                    if np.linalg.norm(dr) < max_roh:
                        bonds[ii].append(jj)
                        bonds[jj].append(ii)
    if uniq_hbond:
        for jj in range(natoms):
            if atype[jj] == h_type:
                if len(bonds[jj]) > 1:
                    orig_bonds = bonds[jj]
                    min_bd = 1e10
                    min_idx = -1
                    for ii in bonds[jj]:
                        dr = posi_diff(box, posis[ii], posis[jj])
                        drr = np.linalg.norm(dr)
                        # print(ii,jj, posis[ii], posis[jj], drr)
                        if drr < min_bd:
                            min_idx = ii
                            min_bd = drr
                    bonds[jj] = [min_idx]
                    orig_bonds.remove(min_idx)
                    # print(min_idx, orig_bonds, bonds[jj])
                    for ii in orig_bonds:
                        bonds[ii].remove(jj)
    return bonds


